"""
MKT Original Commentary — 1 Kings chapters 8–9
Run: python3 scripts/zc-original-1kings-8-9.py

Source data used:
- data/interlinear/1kings.json
- data/translation/glossary-hebrew.json
- data/translation/notes/1kings.json
- data/translation/draft/mediating/1kings.json

Key decisions in this range:
- Ch8 is the longest and theologically densest chapter in Kings: Temple dedication, the Shekinah-cloud, and Solomon's seven-petition prayer
- v12 ʿărāpel (thick darkness): YHWH's dwelling in impenetrable darkness — not absence of light but transcendent hiddenness; LXX reads differently
- v27 rhetorical question: 'Will God truly dwell on the earth?' — the theological problem the whole prayer grapples with
- v46 ʾên ʾādām ʾăšer lōʾ yeḥeṭāʾ: OT's clearest universal sinfulness statement
- Ch9 conditional covenant: the verbatim parallel with ch3 (Gibeon) shows the Deuteronomistic historian's structural intentionality
- v15 hammās (forced labor): same term as 5:13; seeds the complaint of ch12
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS = {
  "8": {
    "1": '<p>The procession of the ark to the Temple opens with <em>ʾāz yaqhēl šəlōmōh</em> — &ldquo;then Solomon assembled.&rdquo; The <em>ʾāz</em> (then/at that time) connects this ceremony to the Temple completion narrative of ch7; both events are framed together as the culmination of the Davidic promise. The assembly is threefold: <em>ziqnê yiśrāʾēl</em> (elders), <em>rāʾšê hammāṭṭôt</em> (heads of the tribes), and <em>nəśîʾê hāʾāḇôt</em> (leaders of the ancestral clans). The hierarchy mirrors the Sinai assembly structure — the whole covenant people, represented through its leadership, gathers for the installation of YHWH&rsquo;s dwelling.</p>',
    "2": '<p><em>Yəraḥ hāʾêtānîm</em> — the month of Ethanim, identified as the seventh month (<em>baḥōdeš haššəḇîʿî</em>). The seventh month is Tishri, the time of the autumn festivals including the Feast of Tabernacles. The narrator notes this twice (v2, v65), signaling the deliberate liturgical timing: the ark&rsquo;s installation coincides with the great harvest festival when all Israel was required to appear before YHWH (Deut 16:16). The Temple dedication is thus a national covenant-renewal at the feast where YHWH&rsquo;s presence among his people was annually celebrated.</p>',
    "3": '<p><em>Wayyiśśəʾû hakkōhănîm ʾet-hāʾārôn</em> — the priests carry the ark. The Levites assisted (v4), but the ark itself was borne by the priests (<em>kōhănîm</em>), as specified in the Sinai instructions for its transportation (Num 4:15 designates the Kohathites to carry the ark, but the priests handled it; the distinction is significant after Uzzah&rsquo;s death in 2 Sam 6:7). The assembly and the procession enact the covenant protocols exactly as prescribed.</p>',
    "4": '<p>The tabernacle (<em>ʾōhel môʿēd</em>) and all its vessels were brought up alongside the ark. The merger of Mosaic and Solomonic cult is explicit here: the portable sanctuary of the wilderness period is retired and its contents absorbed into the permanent Temple. All the <em>kəlê haqqōdeš</em> (holy vessels) that were in the tabernacle — altar, lampstand, incense altar, and the rest — find their place in the new house. The Temple does not replace Moses but fulfills what Moses began.</p>',
    "5": '<p>The scale of sacrifice at the ark&rsquo;s arrival — <em>ṣōʾn ûḇāqār ʾăšer lōʾ-yissāpərû wəlōʾ yimmānû mērōḇ</em> (&ldquo;sheep and oxen that could not be counted or numbered for abundance&rdquo;) — is deliberately reminiscent of David&rsquo;s procession in 2 Samuel 6:13 where oxen and fatted animals were sacrificed after every six steps. The hyperbolic scale signals the magnitude of the event: this is the definitive installation of YHWH&rsquo;s presence.</p>',
    "6": '<p><em>Dəḇîr habbayit</em> — the inner sanctuary, the Holy of Holies. The root <em>dāḇar</em> (to speak) gives this room its name in some etymologies, though others connect it to a Semitic root for back/innermost. The MKT renders it &ldquo;inner sanctuary — the Most Holy Place.&rdquo; The priests brought the ark &ldquo;under the wings of the cherubim (<em>taḥat kanpê hakkərûḇîm</em>).&rdquo; The cherubim, ten cubits tall (6:23-24), stood with wings outstretched; their wingtips met in the center of the room, creating a canopy over the ark. This fulfilled the Sinai instructions where the mercy seat was flanked by cherubim (Exod 25:18-22).</p>',
    "7": '<p><em>Wayyihyû hakkərûḇîm pōrəśîm kənāpayim</em> — the cherubim were spreading wings over the place of the ark. The verb <em>pāraś</em> (spread, extend) used for the cherubim&rsquo;s wings is the same word used for Solomon&rsquo;s prayer posture at v22 (<em>pāraś yādāyw</em>). The wings that shelter the ark and the hands spread in prayer are the same gesture of protective covering — the Temple is architecturally the space of divine shelter and human approach.</p>',
    "8": '<p><em>Wayyiʾārəkû habbaddîm</em> — the poles of the ark were so long that their ends were visible from the Holy Place, though not outside it. The poles (<em>baddîm</em>) were never to be removed according to Exod 25:15. Their projection beyond the curtain is a visual proof of their length, not a violation of Sinai regulation. The ark was carried only by its poles so that no one would touch the sacred object itself — the arrangement maintains the theological protocol that YHWH&rsquo;s presence is approached only on his prescribed terms.</p>',
    "9": '<p><em>ʾÊn bāʾārôn raq šənê luḥôt hāʾăḇānîm</em> — nothing is in the ark except the two stone tablets. The absence of any other object is theologically pointed: by Solomon&rsquo;s time, the jar of manna and Aaron&rsquo;s rod (mentioned in Heb 9:4 as originally deposited before the ark) are gone. The covenant text alone remains. The tablets inscribed at Horeb, encoding the Ten Commandments, are the permanent core of the ark&rsquo;s contents — YHWH&rsquo;s dwelling is grounded in his word, not in relics. The book of Hebrews uses the ark&rsquo;s contents as a typological map of the heavenly sanctuary (Heb 9:3-5).</p>',
    "10": '<p><em>Wayhî bəṣēʾt hakkōhănîm min-haqqōdeš wəhāʿānān mālaʾ ʾet-bêt yhwh</em> — when the priests came out of the Holy Place, the cloud filled the house. The cloud (<em>ʿānān</em>) is the theophanic pillar from the Exodus: YHWH led by cloud by day and fire by night (Exod 13:21). The same cloud descended on the tabernacle at its dedication (Exod 40:34-35) — the Temple dedication at this point is the exact replay of the tabernacle&rsquo;s inaugural moment. YHWH&rsquo;s own presence validates the new house.</p>',
    "11": '<p><em>Wəkāḇôd yhwh mālaʾ ʾet-bêt yhwh</em> — the glory of YHWH filled the house. <em>Kāḇôd</em> (glory, weight) is the regular OT term for the luminous, weighty divine presence — the same word used for the glory that filled the tabernacle at Exod 40:34-35. The priests could not stand to minister: <em>wəlōʾ-yāḵlû hakkōhănîm laʿămōd ləšārēt</em>. The divine presence was not a gentle visitation but an overwhelming filling that rendered normal liturgical activity impossible. Ezekiel will see this same glory depart from the Temple (Ezek 10:18-19) and return in the eschatological temple vision (Ezek 43:4-5).</p>',
    "12": '<p><em>ʾĀmartā liškon bāʿărāpel</em> — &ldquo;you have said that you would dwell in thick darkness.&rdquo; The word <em>ʿărāpel</em> is not ordinary darkness but the impenetrable darkness associated with theophany (Deut 4:11; 5:22 — YHWH spoke from the fire, cloud, and <em>ʿărāpel</em> at Sinai). This is not absence of light but divine hiddenness in transcendence. Solomon is not lamenting that YHWH is obscure; he is affirming that YHWH&rsquo;s decision to be present in the Temple is consistent with his transcendent hiddenness. The visible cloud-filling of v10-11 is the manifestation of this dark-dwelling presence.</p>',
    "13": '<p><em>Bānōh bānîtî bêt zeḇul lāk</em> — &ldquo;I have truly built you an exalted house.&rdquo; The word <em>zeḇul</em> appears only here and in Isa 63:15 (&ldquo;your holy and glorious habitation&rdquo;). It is related to <em>zāḇal</em> (to honor/carry) and conveys elevation and dignity. <em>Mākôn lǝšibteḵā ʿôlāmîm</em> — &ldquo;a dwelling place for your dwelling forever.&rdquo; The word <em>šeḇet</em> (dwelling, sitting) uses the same root as the divine throne — Solomon presents the Temple as the earthly counterpart of YHWH&rsquo;s heavenly throning. The claim will be tested against the rhetorical question of v27.</p>',
    "14": '<p>Solomon turns from addressing the Temple to addressing the assembly: <em>wayyassēb hammelek ʾet-pānāyw</em> — &ldquo;the king turned his face.&rdquo; The gesture of turning is the pivot from Temple-dedication speech to congregational address. The sequence — dedicate the space, then instruct the assembly — follows the pattern of Tabernacle dedication (Exod 40) and Sinai covenant (Exod 19-24). Building is always for the sake of the people&rsquo;s relationship with YHWH, not an end in itself.</p>',
    "15": '<p><em>Bārûk yhwh ʾelōhê yiśrāʾēl ʾăšer dibber bəpîw</em> — &ldquo;blessed be the LORD God of Israel, who spoke with his mouth.&rdquo; The phrase <em>ʾăšer dibber bəpîw ûbəyādô millēʾ</em> — spoken with his mouth and fulfilled with his hand — is a formula of faithful performance. The divine word and its execution are inseparably linked: YHWH&rsquo;s speaking is never merely declarative but always performative. This introduces the historical retrospective (vv15-21) as a record of divine word-fulfillment, grounding the prayer of vv22-53 in demonstrated covenant faithfulness.</p>',
    "16": '<p>The covenant history begins with the Exodus: YHWH did not choose a city in Israel for a Temple from the day he brought Israel out of Egypt, but he chose David. The contrast of city and person is deliberate: YHWH&rsquo;s first choice was a shepherd-king, not a sacred site. The Temple is the consequence of the Davidic election, not its precondition. This subordinates the place to the person — the Temple serves the dynasty, not vice versa. The principle will prove consequential when the Temple is destroyed: YHWH&rsquo;s promise was to David&rsquo;s line, not to the building.</p>',
    "17": '<p><em>Wayhî ʿim-lēḇaḇ dāwid ʾāḇî libənôt bayit</em> — &ldquo;it was in the heart of my father David to build a house.&rdquo; David&rsquo;s intention (<em>lēḇāḇ</em>, heart) is honored even though it was not fulfilled. The narrator&rsquo;s use of <em>lēḇāḇ</em> echoes the theological principle of the royal standard: it is what is &ldquo;in the heart&rdquo; before YHWH that determines the covenant standing of the king (11:4; 15:3,14). David&rsquo;s Temple-intention defines his character before YHWH even in its unfulfillment.</p>',
    "18": '<p>YHWH&rsquo;s response to David: <em>yaʿan ʾăšer hāyâ ʿim-lǝḇāḇǝkā libənôt bayit lišmî hêṭîḇōtā kî hāyâ ʿim-lǝḇāḇǝkā</em> — &ldquo;because it was in your heart to build a house for my name, you did well that it was in your heart.&rdquo; The double occurrence of <em>ʿim-lǝḇāḇǝkā</em> emphasizes that YHWH evaluates the intention itself, not only the deed. The unrealized intention counts as righteous before God. This is not a license for perpetual deferral but an affirmation that covenant faithfulness is ultimately a matter of the heart.</p>',
    "19": '<p><em>Raq ʾattāh lōʾ tibneh habbāyit</em> — &ldquo;nevertheless, you shall not build the house.&rdquo; YHWH&rsquo;s commendation of David&rsquo;s intention is followed immediately by its rejection. The word <em>raq</em> (only, nevertheless) marks the sharp qualification: heart-approval and deed-prohibition coexist. The reason given (2 Sam 7:13: &ldquo;he shall build a house for my name&rdquo;) is that the house belongs to Solomon&rsquo;s covenant identity. The distinction between father and son is theologically productive — it creates the typological pattern of preparation (David) and fulfillment (Solomon) that prefigures the distinction between John the Baptist and Jesus.</p>',
    "20": '<p>Solomon&rsquo;s self-identification: <em>wayyāqam yhwh ʾet-dəḇārô ʾăšer dibber</em> — &ldquo;the LORD has fulfilled his word which he spoke.&rdquo; The verb <em>qûm</em> (rise, stand, be established/fulfilled) used here is the same root as in the Davidic covenant (2 Sam 7:12: <em>wăhăqîmōtî ʾet-zarʿăkā</em>, I will raise up your offspring). Solomon&rsquo;s building of the Temple is itself the fulfillment of the promise. Standing on the throne in v20 and building the house are the twin fulfillments of YHWH&rsquo;s dynastic word.</p>',
    "21": '<p><em>Wayyāśem šām māqôm lāʾārôn ʾăšer šām bərît yhwh</em> — &ldquo;I have made a place there for the ark, in which is the covenant of the LORD.&rdquo; The Temple&rsquo;s definition is minimal and precise: it is the place for the ark. The ark contains the covenant (<em>bərît</em>). The Temple thus is the house of the covenant — YHWH&rsquo;s dwelling is inseparable from his binding covenant commitments to Israel. The entire building program is legitimized by its function as the home of the covenant document, not by architectural grandeur.</p>',
    "22": '<p>Solomon&rsquo;s prayer begins with a physical posture: <em>wayyaʿămōd šəlōmōh lipnê mizbaḥ yhwh neged kol-qəhal yiśrāʾēl wayyiprōś kappāyw haššāmāyim</em> — he stood before the altar and spread his hands toward the heavens. The gesture of <em>pāraś kappāyw</em> (spreading palms) toward heaven is the posture of supplication and dependence — not fists raised in demand but open palms turned upward in receptive petition. The entire assembly witnesses the king&rsquo;s prayer as a representative act: the king prays on behalf of the nation, and the nation is present to receive the answer.</p>',
    "23": '<p>The prayer opens with YHWH&rsquo;s incomparability: <em>ʾên-kāmôk ʾelōhîm baššāmayim mimmaʿal wəʿal-hāʾāreṣ mittāḥat</em> — &ldquo;there is none like you, God, in the heavens above or on the earth beneath.&rdquo; The formula <em>ʾên kāmôk</em> (none like you) is the OT&rsquo;s standard monotheistic assertion (Exod 15:11; Deut 33:26; Ps 86:8). Solomon then defines what makes YHWH incomparable: <em>šōmēr habbərît wəhaḥesed</em> — keeping the covenant and the covenant-loyalty. YHWH&rsquo;s uniqueness is not primarily ontological but relational: he is the God who keeps his promises.</p>',
    "24": '<p>The covenant faithfulness Solomon invokes is specifically the Davidic promise: <em>ʾăšer šāmartā ləʿabdəkā dāwid ʾāḇî ʾēt ʾăšer-dibbar-tā lô</em> — &ldquo;who kept to your servant my father David what you promised him.&rdquo; <em>Dibber bəpîkā ûḇiyadəkā millēʾtā</em> — spoken with your mouth and fulfilled with your hand. The correspondence of word (<em>peh</em>) and deed (<em>yād</em>) is emphasized again as in v15. The prayer&rsquo;s logic: YHWH&rsquo;s past performance grounds the confidence of the present petition.</p>',
    "25": '<p>Solomon transitions from retrospective thanksgiving to present petition: <em>wəʿattāh yhwh ʾelōhê yiśrāʾēl šəmor ləʿabdəkā dāwid ʾāḇî ʾēt ʾăšer dibbar-tā lô</em> — &ldquo;now therefore, keep for your servant David what you promised him.&rdquo; The future continuation of the covenant is conditioned: <em>raq im-yišmərû bānêkā ʾet-darkām lāleket lǝpānay kāʾăšer hālaket lǝpānay</em> — &ldquo;if only your sons keep their way, walking before me as you walked before me.&rdquo; The covenant&rsquo;s perpetuity is real but not unconditional. This condition will prove consequential in ch11.</p>',
    "26": '<p><em>Wəʿattāh ʾelōhê yiśrāʾēl yiʾāmen nāʾ dəḇārəkā</em> — &ldquo;now, O God of Israel, let your word be confirmed.&rdquo; The verb <em>ʾāman</em> (be firm, confirmed, trustworthy) is the root of the Hebrew <em>ʾāmēn</em> — Solomon&rsquo;s request is literally that YHWH&rsquo;s word prove itself to be <em>ʾāmēn</em>. This is a prayer for divine fidelity, not an expression of doubt. To pray for YHWH&rsquo;s word to be confirmed is an act of dependence on the word rather than presumption of its self-evidence.</p>',
    "27": '<p><em>Kî hammeʾumnam yēšēḇ ʾelōhîm ʿal-hāʾāreṣ</em> — &ldquo;but will God truly dwell on the earth?&rdquo; This is the theological question the whole prayer addresses. The adverb <em>meʾumnam</em> (truly, really) signals that what follows is not naïve assumption but a considered theological claim that Solomon himself finds almost incredible. <em>Hinnēh haššāmayim ûšmê haššāmayim lōʾ yəkalkalûkā ʾap kî-habbayit hazzeh ʾăšer bānîtî</em> — even the highest heavens cannot contain you, how much less this house I have built. The question is answered by the very fact of the cloud-filling in vv10-11: YHWH does dwell on the earth, but always on his own terms, always in excess of any human capacity to contain him.</p>',
    "28": '<p><em>Wəpānîtā ʾel-tepillat ʿabdəkā</em> — &ldquo;yet regard the prayer of your servant.&rdquo; Despite the transcendence just affirmed, Solomon petitions that YHWH will &ldquo;turn toward&rdquo; (<em>pānāh ʾel</em>) his prayer. <em>Tepillāh</em> (prayer) and <em>taḥănûnāh</em> (plea for favor) are the two terms Solomon uses to describe the act; <em>taḥănûnāh</em> comes from <em>ḥānan</em> (show grace), implying that what is asked for is unearned mercy, not payment for services rendered. The seven petitions that follow build on this humble foundation.</p>',
    "29": '<p><em>Lihyôt ʿênêkā pətūḥôt ʾel-habbayit hazzeh lāyəlāh wāyôm</em> — &ldquo;that your eyes may be open toward this house night and day.&rdquo; The petition for divine eyes open toward the Temple is a way of saying: let this place be a place where prayer is genuinely heard. The Temple is not magic — it does not automatically guarantee answers — but it is a locus of divine attentiveness. <em>Lišmōaʿ ʾel-hattəpillāh ʾăšer yitpallēl ʿabdəkā ʾel-hammāqôm hazzeh</em> — to hear the prayer toward this place. &ldquo;Toward&rdquo; (<em>ʾel</em>): the Temple is the directional focus for prayer, not the deity&rsquo;s postal address.</p>',
    "30": '<p>The first petition: <em>wəšāmaʿtā ʾel-taḥănat ʿabdəkā wəʿammēkā yiśrāʾēl</em> — hear the plea of your servant and your people Israel when they pray toward this place. <em>Šāmaʿtā hammāqôm haššāmayim</em> — &ldquo;hear from the place of your dwelling, even from heaven, and when you hear, forgive.&rdquo; The critical distinction: prayer is directed toward the Temple, but YHWH hears from heaven. The Temple is not the deity&rsquo;s residence in a local, contained sense — he inhabits heaven — but it is the place where the upward channel of prayer is most reliably open. The phrase &ldquo;hear and forgive&rdquo; (<em>šāmaʿtā wəsālaḥtā</em>) will become the refrain of the seven petitions.</p>',
    "31": '<p>Second petition: judicial oaths. <em>ʾăšer yeḥeṭā ʾîš ləreʿēhû</em> — when one man sins against another and is required to take an oath before the altar. The verb <em>nāśāʾ ʾālāh</em> (lift up a curse/oath) describes a self-imprecatory oath by which a man invokes divine judgment on himself if he is lying (cf. Exod 22:10-11). The Temple altar becomes the locus of judicial procedure — a place where human courts, unable to resolve disputes, appeal to YHWH&rsquo;s tribunal. The request is not that YHWH condemn arbitrarily but that the truth come to light through his judgment.</p>',
    "32": '<p><em>Lišpōt ʿăḇādêkā</em> — &ldquo;to judge your servants.&rdquo; YHWH acts as the supreme court: <em>ləharāšîʿ rāšāʿ lātēt darkô bərōʾšô ûləhaṣdîq ṣaddîq lātēt lô kəṣidqātô</em> — to condemn the guilty and put his conduct on his own head, and to vindicate the righteous by giving him his righteousness. The judicial principle is strict: the guilty bears his own guilt (<em>rōʾš</em>, head) and the innocent receives his <em>ṣidqāh</em> (righteousness, rightness). This petition establishes the Temple as the place where YHWH&rsquo;s justice operates — a function the prophets will later invoke when accusing the Temple authorities of subverting it.</p>',
    "33": '<p>Third petition: military defeat. <em>ʾăšer yinnāgep ʿammēkā yiśrāʾēl lipnê ʾôyēḇ</em> — when Israel is defeated before an enemy because they sinned against you. The causal link between sin and military defeat is explicit: <em>kî yeḥeṭāʾû lāk</em>. The Deuteronomic theology of history runs through all seven petitions — blessing and curse are covenant consequences, not accidents. Yet the petition does not end with the defeat; it anticipates return: <em>wəšābû ʾêlêkā</em> — they will return to you. The prayer operates with the full covenant cycle: sin → judgment → repentance → restoration.</p>',
    "34": '<p><em>Wəsālaḥtā ləḥaṭṭāt ʿammēkā yiśrāʾēl</em> — &ldquo;and forgive the sin of your people Israel.&rdquo; The verb <em>sālaḥ</em> (forgive, pardon) is reserved in the OT for divine forgiveness — humans never forgive with <em>sālaḥ</em>, only YHWH does. The return to the land follows forgiveness; geographic restoration is the external form of covenantal restoration. <em>Wăhăšêḇōtām ʾel-hāʾădāmāh ʾăšer nātattāh lăʾăḇôtām</em> — bring them back to the land you gave to their ancestors. The land promise is embedded in the prayer for military success, showing that land is ultimately a relational-covenantal category, not merely geographical.</p>',
    "35": '<p>Fourth petition: drought. <em>ʾăšer yēʿāṣēr haššāmayim wəlōʾ-yihyeh māṭār</em> — when the sky is shut up and there is no rain because they have sinned against you. The connection between covenant faithfulness and rainfall appears in Deut 11:17: if Israel turns away, YHWH &ldquo;will shut up the heavens so that there will be no rain.&rdquo; The drought that Elijah announces in 17:1 will be precisely this covenantal consequence. Solomon anticipates the future in his prayer — the Temple is not a monument to current prosperity but a resource for covenant crisis.</p>',
    "36": '<p><em>Wəhôrētām ʾet-hadderek haṭṭôḇāh ʾăšer yēlēkû-ḇāh</em> — &ldquo;and teach them the good way in which they should walk.&rdquo; Forgiveness of sin and restoration of rain are accompanied by instruction: YHWH&rsquo;s answer to the prayer for rain is not merely meteorological but educative. <em>Hôrāh</em> (teach, instruct — from <em>yārāh</em>, the same root as <em>tôrāh</em>) here means that YHWH&rsquo;s restoration always comes with direction for the future. Relief from drought is not simply a restoration to the status quo but a renewed invitation to walk in the way.</p>',
    "37": '<p>Fifth petition: famine, plague, enemy. <em>Rāʿāḇ kî-yihyeh bāʾāreṣ deḇer kî-yihyeh šiddāpôn wayyērāqôn ʾarbeh wəḥāsîl kî yihyeh kî yāṣar-lô ʾôyəḇô bəʾereṣ šəʿārāyw</em> — famine, pestilence, blight, mildew, locust or grasshopper, or enemy in the land. The list recalls the covenant curses of Deuteronomy 28:22,38 and the plagues of Egypt. Solomon covers every form of national crisis. <em>Kol-nagaʿ kol-maḥălāh</em> — every plague and sickness: the scope is unlimited, anticipating any future disaster.</p>',
    "38": '<p><em>Kol-tepillāh kol-taḥănûnāh ʾăšer tihyeh ləkol-hāʾādām ləkol-ʿammēkā yiśrāʾēl ʾăšer yēdəʿûn ʾîš negaʿ libābô</em> — &ldquo;every prayer, every plea that may come from any person among all your people Israel, each one knowing the wound of his own heart (<em>negaʿ libābô</em>).&rdquo; <em>Negaʿ lēḇāḇ</em> — the wound or affliction of one&rsquo;s heart — is a uniquely personal, interior register. The prayer encompasses not just national crisis but individual suffering. The Temple is a place for those whose affliction is known only to themselves and to YHWH.</p>',
    "39": '<p><em>Wəʾattāh tišmaʿ haššāmayim mākôn šibteḵā wəsālaḥtā wəʿāśîtā wənātattā lāʾîš kəkol-dərākāyw ʾăšer tēdaʿ ʾet-lǝḇāḇô</em> — &ldquo;and you will hear from heaven your dwelling place, and forgive, and act, and give to each person according to all his ways, as you know his heart.&rdquo; The phrase <em>ʾattāh tēdaʿ ʾet-lǝḇāḇô</em> — you know his heart — is the foundation of the petition. YHWH is the only judge who knows what no human court can know: the interior state of the defendant. The Temple prayer is effective precisely because it reaches the God who searches hearts (Ps 139:23; Jer 17:10).</p>',
    "40": '<p><em>Kî-yirāʾûkā kol-hayyāmîm ʾăšer hēm ḥayyîm ʿal-pənê hāʾădāmāh</em> — &ldquo;that they may fear you all the days that they live on the face of the land.&rdquo; The purpose of answered prayer is not comfort but covenant: the goal of every divine response to suffering is that the people will <em>yārēʾ</em> (fear, reverence) YHWH. Answered prayer is not the end of the relationship — it is the means by which the relationship of covenant fear is maintained across the lifespan.</p>',
    "41": '<p>Sixth petition — the foreigner: <em>wəgam ʾel-hannokrî ʾăšer lōʾ-mēʿammēkā yiśrāʾēl hûʾ ûḇāʾ mēʾereṣ rǝḥôqāh</em> — &ldquo;and also the foreigner who is not of your people Israel, who comes from a far land.&rdquo; The sixth petition explicitly extends the Temple&rsquo;s function beyond Israel to the nations. This is the most universally significant of the seven petitions. The foreigner who hears of YHWH&rsquo;s name and comes to pray toward this house is to be heard. The Temple was designed from its inception for the nations, not only for Israel.</p>',
    "42": '<p><em>Kî-yišməʿûn ʾet-šimkā haggādôl</em> — &ldquo;for they will hear of your great name.&rdquo; The foreigner&rsquo;s basis for approaching is purely report: they have heard. This is the theology of witness: YHWH&rsquo;s acts in history with Israel become the basis for the nations&rsquo; approach to him. The great name (<em>šēm haggādôl</em>) carries the full weight of YHWH&rsquo;s covenantal identity — to pray &ldquo;toward the name&rdquo; is to pray toward the God whose character has been revealed in history.</p>',
    "43": '<p><em>Wəyādeʿû kol-ʿammê hāʾāreṣ ʾet-šəmekā lərāʾtāh ʾōtəkā</em> — &ldquo;that all peoples of the earth may know your name and fear you.&rdquo; The purpose clause universalizes the Temple&rsquo;s mission: the building on Zion is meant to function as YHWH&rsquo;s witness to the nations. Isaiah 56:7 makes this explicit: &ldquo;my house shall be called a house of prayer for all peoples.&rdquo; Jesus quotes this verse in the Temple cleansing (Matt 21:13; Mark 11:17), confronting those who have turned the house of all-nations prayer into a market. The sixth petition of Solomon&rsquo;s prayer is the theological foundation for Jesus&rsquo; action.</p>',
    "44": '<p>Seventh petition: battle-prayer. <em>ʾêt ʾôyəḇāyw ʾăšer tišlaḥennû</em> — against enemies wherever YHWH sends them. <em>Wəhitpallǝlû ʾel-yhwh derek hāʿîr ʾăšer bāḥartā bāh wəhabbayit ʾăšer bānîtî lišmekā</em> — they pray toward the city you chose and the house I built for your name. Two focal points for battle-prayer: the chosen city (Jerusalem) and the Temple. The land-direction of prayer (toward Jerusalem, cf. Dan 6:10) is grounded in YHWH&rsquo;s election of Zion as his dwelling-place, not in any localized magic.</p>',
    "45": '<p><em>Wəšāmaʿtā haššāmayim ʾet-tepillātām wəʾet-taḥănûnātām wəʿāśîtā mišpāṭām</em> — &ldquo;hear from heaven their prayer and their plea, and act on their behalf.&rdquo; <em>Mišpāṭ</em> here means their &ldquo;justice&rdquo; or &ldquo;cause&rdquo; — YHWH is being asked to vindicate Israel in the field as their divine warrior. The battle-prayer petition assumes that Israel&rsquo;s wars are YHWH&rsquo;s wars when fought in covenant faithfulness, and that the outcome depends on divine intervention, not merely human strategy.</p>',
    "47": '<p><em>Wəhēšîḇû ʾel-libābām bāʾāreṣ ʾăšer nišbû-šām</em> — &ldquo;and they return to their senses in the land where they were taken captive.&rdquo; The idiom <em>šûḇ ʾel-lēḇāḇ</em> (return to the heart) is a rare expression for coming to one&rsquo;s senses or gaining self-awareness — it is the interior movement that precedes physical return. The prodigal son&rsquo;s &ldquo;coming to himself&rdquo; in Luke 15:17 is the NT equivalent: repentance as an interior turning before any external action. The eighth petition anticipates the exile and articulates the theology of return that Deuteronomy 30:1-3 had already mapped out.</p>',
    "48": '<p><em>Wəšābû ʾêlêkā ḇəkol-lǝḇāḇām ûḇəkol-napšām</em> — &ldquo;and they return to you with all their heart and soul.&rdquo; The double <em>kol-</em> (all their heart, all their soul) echoes the Shema (Deut 6:5) and Josiah&rsquo;s covenant description (2 Kgs 23:25). Return from exile must be a total reorientation, not merely a geographical relocation. The direction of prayer toward Jerusalem (<em>derek ʾarṣām ʾăšer nātattāh lăʾăḇôtām hāʿîr ʾăšer bāḥartā</em>) maintains covenantal orientation even in the land of the enemy.</p>',
    "49": '<p><em>Wəšāmaʿtā haššāmayim mākôn šibteḵā ʾet-tepillātām wəʾet-taḥănûnātām wəʿāśîtā mišpāṭām</em> — the standard refrain returns: hear from heaven and act on their behalf. The persistence of the refrain across all seven petitions is itself a theological statement: regardless of the form the crisis takes, the pattern of response is the same — YHWH hears from heaven and acts for his covenant people. The variety of crises and the uniformity of response together communicate the covenant&rsquo;s comprehensive scope and YHWH&rsquo;s consistent character.</p>',
    "50": '<p><em>Wəsālaḥtā ləʿammēkā ʾăšer ḥāṭəʾû-lāk</em> — &ldquo;and forgive your people who sinned against you.&rdquo; The final petition concludes the exile section with three acts: forgive (<em>sālaḥ</em>), give them compassion (<em>nātan raḥămîm</em>) before the captors, and may the captors have compassion (<em>riḥămûm</em>). The triple mercy-language (<em>raḥămîm</em> twice) is the prayer&rsquo;s most tender appeal. <em>Raḥămîm</em> comes from <em>reḥem</em> (womb) — it is the most viscerally intimate term for divine compassion in Hebrew, the tenderness of a mother for the child she has carried.</p>',
    "51": '<p><em>Kî ʿammēkā wənaḥălātēkā hēm ʾăšer hôṣētāh mimmīṣrayim</em> — &ldquo;for they are your people and your inheritance, whom you brought out of Egypt.&rdquo; The prayer&rsquo;s final argument is not Israel&rsquo;s merit but their status: they are YHWH&rsquo;s <em>naḥălāh</em> (inheritance, portion). The Exodus is the constitutive act that made Israel YHWH&rsquo;s personal possession. Even in the depths of exile, the Exodus identity is the ground of the appeal. Paul will apply the same logic in Rom 11:2 — &ldquo;God has not rejected his people whom he foreknew&rdquo; — where the election grounds the guarantee of restoration.</p>',
    "52": '<p><em>Wihyû ʿênêkā pǝtūḥôt ʾel-taḥănat ʿabdǝkā wǝʾel-taḥănat ʿammǝkā yiśrāʾēl lišmōaʿ ʾălêhem bǝkōl qorʾām ʾêlêkā</em> — &ldquo;may your eyes be open to the plea of your servant and your people Israel, listening to them whenever they call on you.&rdquo; Solomon frames the prayer&rsquo;s close with the same image with which it opened (v29): divine eyes open. The inclusio of v29-52 is intentional — the whole prayer is bracketed by the image of YHWH&rsquo;s attentive eyes, his seeing-and-hearing turned toward the covenant people&rsquo;s prayers.</p>',
    "53": '<p><em>Kî ʾattāh hibdaltām ləkā lǝnaḥălāh</em> — &ldquo;for you set them apart as your inheritance.&rdquo; The closing argument of the prayer: Israel was separated by YHWH himself from all peoples, through Moses, from Egypt. The verb <em>bādal</em> (separate, set apart) is the priestly vocabulary of holiness — what is holy is what has been separated for YHWH. Solomon&rsquo;s final warrant for answered prayer is not human righteousness but divine election: YHWH made Israel his own, and the Temple prayer trusts that he will prove it by responding.</p>',
    "54": '<p>As Solomon finishes the prayer, he rises from his knees (<em>min-hakkōraʿ</em>). The prostration on knees with hands spread toward heaven was his physical posture throughout the prayer (v22, implied in v54). The prayer has been an act of the whole body. <em>Wayyāqom mippənê mizbaḥ yhwh</em> — he rose from before the altar of YHWH. The completion of prayer is marked by standing — an end to petition, a turn toward blessing.</p>',
    "55": '<p><em>Waybarek ʾet kol-qəhal yiśrāʾēl qôl gādôl</em> — &ldquo;and he blessed all the assembly of Israel with a loud voice.&rdquo; The king as covenant mediator blesses the assembly after interceding for them. The loud voice (<em>qôl gādôl</em>) signals that the blessing is public and declaratory, not whispered privately. The priestly parallel is the Aaronic blessing (Num 6:22-27): the one who stands between God and people turns from prayer to pronounce YHWH&rsquo;s favor over them.</p>',
    "56": '<p><em>Bārûk yhwh ʾăšer nātan mənûḥāh ləʿammô yiśrāʾēl</em> — &ldquo;blessed be the LORD who has given rest to his people Israel.&rdquo; <em>Mənûḥāh</em> (rest, settled peace) is the distinctive Deuteronomic concept that governs the whole Temple enterprise — the Temple was built only after Israel had rest from enemies (Deut 12:10-11). The rest is now fulfilled. <em>Lōʾ nāpal dāḇār ʾeḥād mikkol dəḇārô haṭṭôḇ ʾăšer dibber bəyad mōšeh ʿabdô</em> — not one word has fallen from all his good word that he spoke through his servant Moses. Every promise made through Moses has been fulfilled. This is the theological horizon against which the rest of Kings — where promise after promise will be conditionally revoked — must be read.</p>',
    "57": '<p><em>Yihî yhwh ʾelōhênû ʿimmānû kāʾăšer hāyāh ʿim-ʾăḇōtênû</em> — &ldquo;may the LORD our God be with us, as he was with our fathers.&rdquo; The blessing turns into a prayer for continuity. <em>ʿImmānû</em> (with us) — the Immanuel promise in seed form. The request for YHWH&rsquo;s presence with the next generation, as with the former generation, structures the covenant as a living relationship across time rather than a static possession.</p>',
    "58": '<p><em>Lǝhaṭṭôt lǝḇāḇênû ʾêlāyw</em> — &ldquo;that he may incline our hearts to himself.&rdquo; The verb <em>nāṭāh</em> (incline, turn) applied to the heart is theologically significant: the request is not merely that YHWH instruct the people but that he actively orient their inner life toward himself. This anticipates the new covenant promise of Jeremiah 31:33 (&ldquo;I will put my law within them and write it on their hearts&rdquo;) and Ezekiel 36:26-27 (&ldquo;I will give you a new heart... and I will put my Spirit within you and cause you to walk in my statutes&rdquo;). Solomon&rsquo;s prayer for a turned heart is answered definitively only in the new covenant.</p>',
    "59": '<p><em>Wihyû dəḇāray ʾēlleh ʾăšer hitḥannantî lipnê yhwh qərōḇîm ʾel-yhwh ʾelōhênû</em> — &ldquo;and may these words of mine, with which I have made supplication before the LORD, be near to the LORD our God.&rdquo; The prayer that these prayers be near to YHWH is itself a prayer — a recursive petition that the act of prayer be effective. <em>Yôm wālāylāh</em> — day and night: constant divine attentiveness, not seasonal or intermittent. The priestly service in the Temple operated continuously; Solomon&rsquo;s prayer hopes for a corresponding divine attentiveness that never lapses.</p>',
    "60": '<p><em>Lǝmaʿan dāʿat kol-ʿammê hāʾāreṣ kî yhwh hûʾ hāʾelōhîm ʾên ʿôd</em> — &ldquo;that all peoples of the earth may know that the LORD is God; there is no other.&rdquo; The missional purpose clause of the entire Temple program: all nations coming to know the exclusive identity of YHWH as the only God. The formula <em>ʾên ʿôd</em> (there is no other) is the distinctive assertion of Deutero-Isaiah (Isa 45:5,6,14,18,21,22; 46:9). Israel&rsquo;s faithfulness is not merely self-interested covenant compliance — it is the means by which the nations learn monotheism.</p>',
    "61": '<p><em>Wihyeh lǝḇabkem šālēm ʿim yhwh ʾelōhênû</em> — &ldquo;let your heart be wholly devoted (<em>šālēm</em>) to the LORD our God.&rdquo; <em>Lēḇāḇ šālēm</em> — a complete, undivided heart. The noun <em>šālem</em> (whole, complete, at peace) is related to <em>šālôm</em> and describes a heart that is not divided between YHWH and other loyalties. This is the standard against which the Deuteronomistic Historian will assess every subsequent king (11:4; 15:3,14; 2 Kgs 20:3). Solomon himself will fail it (11:4: &ldquo;his heart was not wholly devoted to YHWH&rdquo; — using the same phrase).</p>',
    "62": '<p>The prayer and blessing complete, the entire community turns to sacrifice: <em>wəhamelek wəkol-yiśrāʾēl ʿimmô zōḇəḥîm zeḇaḥ lipnê yhwh</em> — the king and all Israel offering sacrifice before YHWH. The transition from word (prayer) to act (sacrifice) is characteristic of covenant ceremony. The spoken covenant commitments are sealed in blood.</p>',
    "63": '<p>The scale of Solomon&rsquo;s peace offerings: 22,000 cattle and 120,000 sheep. <em>Šəlāmîm</em> (peace offerings) are offerings in which the worshipper shares in eating the meat — they are communal, festive, covenant-meals, not wholly burnt. The enormous scale signals that the Temple dedication is the greatest covenant celebration since Sinai. <em>Wayyaḥnōk hamelek ʾet-bêt yhwh</em> — the king dedicated (<em>ḥānak</em>) the house. <em>Ḥanukkah</em> comes from this root; dedication in Israel is always a covenant act.</p>',
    "64": '<p>The bronze altar was insufficient for the volume of offerings, so Solomon consecrated the middle of the court for additional burnt offerings, grain offerings, and the fat of peace offerings. The divine acceptance of the dedication overflows its normal liturgical vessels — the quantity of response exceeds what the allocated space can hold. This overspill is itself a statement about the abundance of the occasion.</p>',
    "65": '<p>The feast lasted fourteen days: seven days for the dedication of the altar and seven days for the Feast of Tabernacles (<em>ḥaggāh šiḇʿat yāmîm wəšiḇʿat yāmîm</em>). The two sevens make one great festival of fourteen days. <em>ʿōḏ habbôʾ ḥamāt ʿaḏ-naḥal miṣrayim</em> — from the entrance of Hamath to the Brook of Egypt, the ideal borders of Israel (Num 13:21; Amos 6:14). The geographic scope of the assembly matches the theological scope of the prayer: all Israel, from its ideal northern to its southern boundary.</p>',
    "66": '<p>On the eighth day (<em>bayyôm haššəmînî</em>) the people went home. The eighth day after a seven-day festival is the day of dismissal — but also, in priestly theology, the day that points beyond the cycle: seven represents the complete created week; eight is the eschatological new creation. The people departed <em>śəmēḥîm wəṭôḇê lēḇ ʿal kol-haṭṭôḇāh ʾăšer ʿāśāh yhwh lǝdāwid ʿabdô ûlǝyiśrāʾēl ʿammô</em> — &ldquo;joyful and glad of heart for all the good that YHWH had done for David his servant and for Israel his people.&rdquo; Joy is the right theological response to what YHWH has done.</p>'
  },
  "9": {
    "1": '<p><em>Wayəhî kəkallôt šəlōmōh libənôt</em> — &ldquo;when Solomon had finished building.&rdquo; The verb <em>kālāh</em> (finish, complete) brackets the entire building program: 7:51 used the same word for the individual structures; here it applies to the whole complex (Temple + palace + everything he desired, <em>ḥēpeṣ</em>). The completion of the program creates the structural conditions for YHWH&rsquo;s second appearance — divine response to completed human faithfulness.</p>',
    "2": '<p><em>Wayyērāʾ yhwh ʾel-šəlōmōh šēnît</em> — &ldquo;the LORD appeared to Solomon a second time.&rdquo; The first appearance was at Gibeon before the Temple project (3:5-15). The symmetry is deliberate: YHWH appeared to commission Solomon at the beginning of his reign, and appears again to evaluate and condition its continuation at the Temple&rsquo;s completion. The narrator&rsquo;s <em>kaʾăšer nirʾāh ʾêlāyw bəgiḇʿôn</em> — &ldquo;as he had appeared to him at Gibeon&rdquo; — signals the reader to compare the two appearances as a pair.</p>',
    "3": '<p><em>Šāmaʿtî ʾet-tepillatǝkā wǝʾet-taḥinatǝkā ʾăšer hitḥannantā lǝpānāy</em> — &ldquo;I have heard your prayer and your plea that you made before me.&rdquo; YHWH&rsquo;s first word is confirmation: the dedication prayer was received. <em>Qiddaštî ʾet-habbayit hazzeh ʾăšer bānîtā lāśûm-šəmî šām ʿaḏ-ʿôlām</em> — &ldquo;I have consecrated this house to put my name there forever.&rdquo; <em>Qādaš</em> (consecrate, make holy) in the Piel — YHWH himself performs the consecration, not Solomon&rsquo;s ritual. The Temple is holy because YHWH has declared it so, not because of the building&rsquo;s quality.</p>',
    "4": '<p>The conditional covenant resumes: <em>wəʾattāh ʾim-tēlek lǝpānay kāʾăšer hālek dāwid ʾāḇîkā</em> — &ldquo;as for you, if you walk before me as your father David walked.&rdquo; The verb <em>hālak lǝpānāy</em> (walk before me) is the key covenant-walking idiom: it describes the totality of covenant life lived under YHWH&rsquo;s gaze. <em>Bǝtom-lēḇāḇ ûḇəyōšer</em> — &ldquo;with integrity of heart and uprightness.&rdquo; <em>Tōm</em> (wholeness, completeness) and <em>yōšer</em> (uprightness, straightness) define Davidic covenant faithfulness. Both terms are internal — the condition is not merely external observance.</p>',
    "5": '<p><em>Wăhăqîmōtî ʾet-kissēʾ mamlaktǝkā ʿal-yiśrāʾēl lǝʿōlām</em> — &ldquo;I will establish your royal throne over Israel forever.&rdquo; The promise of perpetual dynasty (<em>lǝʿōlām</em>) was given unconditionally to David in 2 Samuel 7:13-16. Here it is given conditionally to Solomon — a key distinction in Deuteronomistic theology. The unconditional promise guarantees the dynasty will not finally fail; the conditional form governs whether individual kings participate in its blessing. The tension between unconditional (Davidic) and conditional (Mosaic) covenant strands runs through all of Kings.</p>',
    "6": '<p><em>ʾIm-šôḇ tāšûḇûn ʾattem ûḇənêkem mēʾaḥărāy</em> — &ldquo;but if you utterly turn away, you and your sons, from following me.&rdquo; The emphatic double infinitive <em>šôḇ tāšûḇûn</em> (turn, you will turn) intensifies the warning. The apostasy envisioned is deliberate and complete, not accidental or partial. The condition is relational abandonment — <em>mēʾaḥărāy</em> (from following me) — not merely ritual failure. The covenant is broken by turning away from YHWH himself, not merely by neglecting individual commandments.</p>',
    "7": '<p><em>Wəhikrattî ʾet-yiśrāʾēl mēʿal pənê hāʾădāmāh</em> — &ldquo;I will cut off Israel from the face of the land.&rdquo; The verb <em>kārat</em> (cut) is the covenant word: to be cut off from the covenant is to be cut off from the land. <em>Wəhabbayit ʾăšer qiddaštî lišmî ʾašallaḥ mēʿal pānāy</em> — &ldquo;the house I have consecrated for my name I will cast from my sight.&rdquo; <em>Šālaḥ mēʿal pānāy</em> (cast from before my face) — the Temple&rsquo;s consecration is reversible. What YHWH dedicated he can also un-dedicate. This is the theological preparation for the destruction narrated in 2 Kings 25.</p>',
    "8": '<p><em>Wǝhabbayit hazzeh yihyeh ʿelyôn</em> — the house will become a ruin (MT reads &ldquo;high/exalted&rdquo; but the context requires desolation; some mss and LXX support &ldquo;heap of ruins&rdquo;). <em>Kol-ʿōḇēr ʿālāyw yiššōm wəyišrōq</em> — &ldquo;everyone who passes by it will be appalled and will hiss.&rdquo; The desolation of Zion becomes a theological spectacle for the nations — the very nations who were invited to pray toward the house will pass by its ruins in horror. Jeremiah uses this exact language of hissing-and-amazement (Jer 18:16; 19:8).</p>',
    "9": '<p><em>Wəʾāmərû ʿal-meh ʿāśāh yhwh kākāh lāʾāreṣ hazzōʾt ûlabbayit hazzeh</em> — &ldquo;they will say: why did the LORD do this to this land and this house?&rdquo; The question the nations will ask and the answer they will receive constitute a brief catechism: sin → abandonment → judgment. <em>Wəhiḥězîqû bēʾlōhîm ʾăḥērîm</em> — &ldquo;because they held on to other gods.&rdquo; The root of the catastrophe is not political or military but covenantal. The Temple&rsquo;s destruction will serve as testimony to the nations of the same monotheistic truth the Temple&rsquo;s dedication prayed for (8:60).</p>',
    "10": '<p>Solomon gave Hiram of Tyre twenty cities in Galilee (<em>Gālîl</em>) in payment for timber and gold. The geographic designation <em>ʾereṣ haggālîl</em> appears here for the first time in Scripture. Isaiah 9:1 designates this same region (&ldquo;Galilee of the nations&rdquo;) as the place where the people sitting in darkness will see a great light — the very territory alienated by Solomon becomes the setting for Jesus&rsquo; Galilean ministry.</p>',
    "11": '<p>Hiram&rsquo;s inspection of the cities and his verdict: <em>mah-hehārim hāʾēlleh ʾăšer nātattāh lî ʾāḥî</em> — &ldquo;what are these cities you have given me, my brother?&rdquo; The irony of <em>ʾāḥî</em> (my brother) — treaty-partnership language — combined with the dismissive question creates a tense diplomatic moment. The relationship with Tyre that was so productive for the Temple project ends with a rebuke of Solomon&rsquo;s payment. The narrator records it without exculpating Solomon.</p>',
    "12": '<p>Hiram named the cities <em>ʾereṣ Kāḇûl</em> — the land of Cabul, meaning possibly &ldquo;good-for-nothing&rdquo; or &ldquo;like nothing&rdquo; (interpreted as wordplay on <em>kā-ḇal</em>, meaning &ldquo;as nothing&rdquo;). The naming is an act of contempt, recorded in the text as permanent memory of the transaction. The Temple was built with Hiram&rsquo;s premium materials; Solomon&rsquo;s payment was substandard. The narrator does not editorialize, but the contrast is stark.</p>',
    "13": '<p><em>Wayyišlaḥ ləhamelek meʾāh wəʿeśrîm kikkār zāhāb</em> — Hiram sent 120 talents of gold. Despite his displeasure, the alliance continues. The transaction is completed, the gold is paid. The larger economic framework of Solomon&rsquo;s reign — massive imports funded by tribute, trade, and alienation of land — is starting to accumulate. By ch11, the weight of these obligations will be visible in the structural cracks of his kingdom.</p>',
    "14": '<p>The 120 talents of gold are the only explicit payment figure for the Hiram alliance. Whether this represents full settlement or partial payment is not specified. The brevity of the record invites the reader to hold the exchange in mind — an international partnership for the Temple required significant and apparently imperfect earthly economics.</p>',
    "15": '<p><em>Wəzeh dəḇar-hammās ʾăšer heʿĕlāh hammelek šəlōmōh</em> — &ldquo;this is the account of the forced labor (<em>hammās</em>) that King Solomon levied.&rdquo; <em>Mas</em> (forced labor, levy, work-gang) is the same word used for Israel&rsquo;s labor under Pharaoh in Exodus 1:11 — <em>śārê missîm</em> (taskmasters of the forced labor). The verbal echo is not accidental. Solomon&rsquo;s building program, for all its theological grandeur, uses the infrastructure of oppression. The complaint that will break apart the kingdom in ch12 is rooted here.</p>',
    "16": '<p>The list of building projects: Jerusalem&rsquo;s Millo (<em>hammillōʾ</em>, the fill/terrace structure), the wall, Hazor, Megiddo, Gezer. Pharaoh had captured and burned Gezer, killing its Canaanite inhabitants, and gave it as a dowry to Solomon with his daughter. The international alliance that enables the Temple project is simultaneously a political-dynastic arrangement that brings Egyptian royal daughters into the Davidic household — an entanglement that 11:1-8 will identify as Solomon&rsquo;s undoing.</p>',
    "17": '<p>Gezer, Lower Beth-horon, Baalath — the construction program continues down the Shephelah and into the coastal plain. The scale of the building program required the forced labor levy of v15. The geographic spread demonstrates Solomon&rsquo;s administrative reach across the whole land, but also the human cost of maintaining it.</p>',
    "18": '<p>Tadmor in the wilderness (possibly Palmyra, the great desert caravan city) and all the storage cities of Solomon. The extension of Solomon&rsquo;s building to Tadmor, far northeast of Israel, represents the empire&rsquo;s maximal geographic extent — a detail preserved here as evidence of unprecedented scale.</p>',
    "19": '<p>The <em>ʿārê hammiskənôt</em> (storage cities), chariot cities, and cavalry cities, and &ldquo;all of Solomon&rsquo;s desires that he desired to build.&rdquo; The phrase <em>kol-ḥēšeq šəlōmōh ʾăšer ḥāšaq</em> — all his desire that he desired — is the language of appetite. The same word (<em>ḥēšeq</em>) appears in 9:1 for the things he desired to build. The echo suggests that Solomon&rsquo;s construction program is driven by personal appetite as much as covenant obligation.</p>',
    "20": '<p>The forced labor of vv20-22 carefully distinguishes its source: <em>kol-hāʿām hannôtār min-hāʾĕmōrî hahittî happərizzî haḥiwwî wəhayyəḇûsî ʾăšer lōʾ-mibənê yiśrāʾēl hēmmāh</em> — all the remaining Canaanite peoples who were not Israelites. The Israelites were exempt from the permanent-slave labor (v22). The structural distinction matters for the narrative: the temporary labor levy in 5:13-14 applied to Israel; the permanent slave-labor applies to the remnant Canaanites, fulfilling the conquest&rsquo;s unfinished business (Joshua 17:13).</p>',
    "21": '<p><em>Bənêhem ʾăšer nôtərû ʾaḥărêhem bāʾāreṣ</em> — &ldquo;their descendants who remained in the land.&rdquo; The hereditary nature of the slave-labor force: conquest-survivors and their children. <em>Wayaʿălēm šəlōmōh ləmas ʿōḇēd</em> — Solomon imposed on them a slave-labor force that remains to this day. The parenthetical &ldquo;to this day&rdquo; is the narrator&rsquo;s signal that this arrangement was still operating when the history was written.</p>',
    "22": '<p>But from the Israelites (<em>ûmibbənê yiśrāʾēl lōʾ-nātan šəlōmōh ʿāḇed</em>) Solomon made no slaves. They were the military corps: men of war, commanders, officers, cavalry-chiefs. The Israelite/Canaanite distinction in the forced-labor system is preserved as a matter of record. But the record of 5:13 (a 30,000-man labor levy from Israel) complicates the clean picture, suggesting that the distinction was not always honored in practice.</p>',
    "23": '<p>The administrative structure: 550 overseers (<em>śārê hannǝṣiḇîm</em>) over the workforce, supervising the labor. The Hebrew gives both 550 (here) and 3,300 in 5:16 — a discrepancy that Chronicles reconciles by giving a combined figure. The administrative personnel required to manage Solomon&rsquo;s building program was itself substantial, a sub-bureaucracy of supervisors over workers.</p>',
    "24": '<p>Pharaoh&rsquo;s daughter moved from the City of David to her own house that Solomon had built for her, after which Solomon built the Millo. The sequence suggests the Millo was completed as part of the palace complex for his Egyptian wife. The narrator notes this without comment, but the placement — immediately after the labor-levy discussion — frames the Egyptian marriage as part of the economic-political entanglement that required the forced labor program.</p>',
    "25": '<p>Three times a year Solomon offered burnt offerings and peace offerings on the altar he built to YHWH — presumably at the three pilgrimage festivals (Passover, Weeks, Tabernacles; cf. Deut 16:16). <em>Wəhiqṭîr ʾittô ʾăšer ʿal-pənê yhwh</em> — &ldquo;and burning incense before YHWH.&rdquo; Solomon&rsquo;s personal cultic performance is noted as regular and correct — he fulfilled the prescribed ritual calendar. The narrator&rsquo;s notice is bittersweet: the king who will introduce apostate shrines in ch11 is, at this point, still keeping the covenant liturgical calendar.</p>',
    "26": '<p>Solomon built a fleet at Ezion-geber (<em>ʿeṣyôn geber</em>) on the shore of the Reed Sea (<em>yam sûp</em>) in the land of Edom. Ezion-geber (modern Aqaba) is the northern tip of the Gulf of Aqaba — the maritime route to Arabia, East Africa, and India. David had conquered Edom (2 Sam 8:14), giving Solomon access to this port. The Red Sea fleet represents the empire&rsquo;s commercial ambition made geographic: the domain of David&rsquo;s military conquest becomes the base of Solomon&rsquo;s commercial enterprise.</p>',
    "27": '<p>Hiram sent his servants alongside Solomon&rsquo;s servants: <em>ʾanšê yōdəʿê hayyām</em> — men who knew the sea. The Israelites were not historically a maritime people (unlike Phoenicia); the partnership with Hiram provided the expertise. The shared fleet is a joint venture — Solomon&rsquo;s gold, Hiram&rsquo;s seamanship. The economic partnership that built the Temple is extended to global commerce.</p>',
    "28": '<p>The fleet went to Ophir (<em>ʾôpîr</em>) and brought back 420 talents of gold. Ophir&rsquo;s location is uncertain (Somalia, south Arabia, India, and Zimbabwe have all been proposed), but &ldquo;gold of Ophir&rdquo; became a byword for the finest gold in the ancient world (Ps 45:9; Job 22:24; Isa 13:12). The 420 (or 450, per 2 Chr 8:18) talents represent an enormous haul. The empire&rsquo;s wealth is as much international-commercial as it is tribute-based.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '1kings')
    merge_comm(existing, KINGS)
    save_comm('mkt-original', '1kings', existing)
    total = sum(len(v) for v in KINGS.values())
    print(f'1kings mkt-original ch8-9: wrote {total} verses')

if __name__ == '__main__':
    main()
